<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Desktop Environment</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Ubuntu, sans-serif;
      background: #0d0d0d;
      color: #ffffff;
      overflow: hidden;
    }

    #desktop {
      width: 100vw;
      height: 100vh;
      background: linear-gradient(135deg, #1a1a1a 0%, #0d0d0d 100%);
      display: flex;
      flex-direction: column;
    }

    #taskbar {
      background: rgba(20, 20, 20, 0.95);
      border-top: 1px solid #333;
      padding: 8px 12px;
      display: flex;
      gap: 8px;
      height: 50px;
      align-items: center;
      flex-shrink: 0;
    }

    .taskbar-btn {
      background: linear-gradient(135deg, #2d2d2d, #1a1a1a);
      border: 1px solid #444;
      color: #fff;
      padding: 8px 16px;
      border-radius: 4px;
      cursor: pointer;
      font-size: 13px;
      transition: all 0.2s;
    }

    .taskbar-btn:hover {
      background: linear-gradient(135deg, #3d3d3d, #2a2a2a);
      border-color: #555;
    }

    .taskbar-btn:active {
      transform: scale(0.98);
    }

    #desktop-area {
      flex: 1;
      position: relative;
      overflow: hidden;
    }

    .window {
      position: absolute;
      background: #1e1e1e;
      border: 1px solid #333;
      border-radius: 6px;
      box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
      display: none;
      flex-direction: column;
      z-index: 100;
      width: 600px;
      height: 400px;
      min-width: 360px;
      min-height: 240px;
    }

    .window.active {
      display: flex;
    }

    .window:nth-of-type(1) {
      top: 80px;
      left: 60px;
    }

    .window:nth-of-type(2) {
      top: 120px;
      left: 120px;
    }

    .window-titlebar {
      background: linear-gradient(90deg, #2d2d2d, #1a1a1a);
      border-bottom: 1px solid #333;
      padding: 12px 16px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      cursor: move;
      border-radius: 6px 6px 0 0;
      user-select: none;
      flex-shrink: 0;
    }

    .window-title {
      font-weight: 500;
      font-size: 14px;
    }

    .win-close {
      background: #e74c3c;
      border: none;
      color: white;
      width: 24px;
      height: 24px;
      border-radius: 3px;
      cursor: pointer;
      font-size: 12px;
      font-weight: bold;
      transition: background 0.2s;
    }

    .win-close:hover {
      background: #c0392b;
    }

    .window-content {
      flex: 1;
      overflow: auto;
      display: flex;
      flex-direction: column;
    }

    #files-path {
      background: #2d2d2d;
      border-bottom: 1px solid #333;
      padding: 8px 12px;
      font-size: 13px;
      font-family: monospace;
      color: #aaa;
      flex-shrink: 0;
    }

    #files-controls {
      display: flex;
      gap: 8px;
      padding: 8px 12px;
      background: #242424;
      border-bottom: 1px solid #333;
      flex-shrink: 0;
    }

    .files-btn {
      background: #2d2d2d;
      border: 1px solid #444;
      color: #fff;
      padding: 6px 12px;
      border-radius: 3px;
      cursor: pointer;
      font-size: 12px;
      transition: all 0.2s;
    }

    .files-btn:hover {
      background: #3d3d3d;
    }

    #files-list {
      flex: 1;
      overflow-y: auto;
      padding: 0;
    }

    .fs-item {
      padding: 10px 12px;
      cursor: pointer;
      user-select: none;
      transition: background 0.1s;
      border-bottom: 1px solid #2a2a2a;
    }

    .fs-item:hover {
      background: #2d2d2d;
    }

    .fs-item.folder::before {
      content: '📁 ';
    }

    .fs-item.file::before {
      content: '📄 ';
    }

    #tabs {
      display: flex;
      gap: 2px;
      background: #242424;
      border-bottom: 1px solid #333;
      padding: 4px;
      overflow-x: auto;
      flex-shrink: 0;
      align-items: center;
    }

    .tab {
      background: #2d2d2d;
      border: 1px solid #333;
      color: #aaa;
      padding: 8px 16px;
      cursor: pointer;
      border-radius: 3px 3px 0 0;
      font-size: 12px;
      white-space: nowrap;
      transition: all 0.2s;
      border-bottom: none;
    }

    .tab:hover {
      background: #3d3d3d;
      color: #fff;
    }

    .tab.active {
      background: #1e1e1e;
      color: #fff;
      border: 1px solid #333;
      border-bottom: 2px solid #0066cc;
    }

    #new-tab {
      background: #2d2d2d;
      border: 1px solid #333;
      color: #aaa;
      padding: 8px 12px;
      cursor: pointer;
      border-radius: 3px;
      font-size: 12px;
      transition: all 0.2s;
      flex-shrink: 0;
      margin-left: auto;
      margin-right: 4px;
    }

    #new-tab:hover {
      background: #3d3d3d;
      color: #fff;
    }

    #editor {
      flex: 1;
      background: #1e1e1e;
      color: #e0e0e0;
      border: none;
      padding: 12px;
      font-family: 'Courier New', monospace;
      font-size: 13px;
      resize: none;
      outline: none;
    }

    #notepad-window .window-content {
      padding: 0;
    }

    #files-window .window-content {
      padding: 0;
    }
  </style>
</head>
<body>
  <div id="desktop">
    <div id="taskbar">
      <button id="open-files" class="taskbar-btn">📁 Files</button>
      <button id="open-notepad" class="taskbar-btn">📝 Notepad</button>
    </div>
    <div id="desktop-area">
      <div id="files-window" class="window">
        <div class="window-titlebar">
          <span class="window-title">Files</span>
          <button class="win-close">×</button>
        </div>
        <div id="files-path"></div>
        <div id="files-controls">
          <button id="files-up" class="files-btn">← Up</button>
        </div>
        <div id="files-list" class="window-content"></div>
      </div>

      <div id="notepad-window" class="window">
        <div class="window-titlebar">
          <span class="window-title">Notepad</span>
          <button class="win-close">×</button>
        </div>
        <div id="tabs"></div>
        <button id="new-tab">+ New</button>
        <textarea id="editor"></textarea>
      </div>
    </div>
  </div>

  <script>
    const filesystem = {
      '/': ['bin', 'etc', 'home', 'usr', 'var'],
      '/bin': ['bash', 'cat', 'ls', 'pwd'],
      '/etc': ['config', 'passwd'],
      '/home': ['user'],
      '/home/user': ['Documents', 'Downloads', 'Pictures', 'readme.txt'],
      '/home/user/Documents': ['project.txt', 'notes.txt'],
      '/home/user/Downloads': ['file1.zip', 'file2.pdf'],
      '/home/user/Pictures': ['photo1.jpg', 'photo2.jpg'],
      '/usr': ['bin', 'lib', 'share'],
      '/usr/bin': ['python', 'node', 'git'],
      '/usr/lib': ['libc.so.6', 'libm.so.6'],
      '/usr/share': ['doc', 'man'],
      '/var': ['log', 'cache', 'tmp'],
      '/var/log': ['system.log', 'auth.log'],
      '/var/cache': ['apt', 'npm'],
      '/var/tmp': []
    };

    let currentPath = '/';
    let tabs = [];
    let activeTabId = null;

    function isFolder(path, name) {
      const fullPath = path === '/' ? '/' + name : path + '/' + name;
      return filesystem.hasOwnProperty(fullPath);
    }

    function displayFiles() {
      const pathEl = document.getElementById('files-path');
      const listEl = document.getElementById('files-list');

      pathEl.textContent = currentPath;
      listEl.innerHTML = '';

      const items = filesystem[currentPath] || [];
      items.forEach(name => {
        const div = document.createElement('div');
        div.className = 'fs-item ' + (isFolder(currentPath, name) ? 'folder' : 'file');
        div.textContent = name;

        div.addEventListener('dblclick', () => {
          if (isFolder(currentPath, name)) {
            currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
            displayFiles();
          }
        });

        listEl.appendChild(div);
      });
    }

    document.getElementById('files-up').addEventListener('click', () => {
      if (currentPath !== '/') {
        currentPath = currentPath.substring(0, currentPath.lastIndexOf('/')) || '/';
        displayFiles();
      }
    });

    function loadNotepadState() {
      const saved = localStorage.getItem('notepad-state');
      if (saved) {
        try {
          const state = JSON.parse(saved);
          tabs = state.tabs || [];
          activeTabId = state.activeTabId || null;
        } catch (e) {
          tabs = [];
          activeTabId = null;
        }
      }
      if (tabs.length === 0) {
        addTab();
      }
    }

    function saveNotepadState() {
      localStorage.setItem('notepad-state', JSON.stringify({
        tabs,
        activeTabId
      }));
    }

    function addTab() {
      const id = Date.now().toString();
      tabs.push({ id, title: 'Untitled', content: '' });
      activeTabId = id;
      renderTabs();
      updateEditor();
      saveNotepadState();
    }

    function renderTabs() {
      const tabsContainer = document.getElementById('tabs');
      tabsContainer.innerHTML = '';

      tabs.forEach(tab => {
        const tabEl = document.createElement('div');
        tabEl.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
        tabEl.textContent = tab.title;

        tabEl.addEventListener('click', () => {
          activeTabId = tab.id;
          renderTabs();
          updateEditor();
        });

        tabsContainer.appendChild(tabEl);
      });

      const newBtn = document.getElementById('new-tab');
      if (newBtn.parentElement.id !== 'tabs') {
        tabsContainer.appendChild(newBtn);
      }
    }

    function updateEditor() {
      const editor = document.getElementById('editor');
      const tab = tabs.find(t => t.id === activeTabId);
      if (tab) {
        editor.value = tab.content;
      }
    }

    document.getElementById('editor').addEventListener('input', (e) => {
      const tab = tabs.find(t => t.id === activeTabId);
      if (tab) {
        tab.content = e.target.value;
        saveNotepadState();
      }
    });

    document.getElementById('new-tab').addEventListener('click', () => {
      addTab();
    });

    function openWindow(windowEl) {
      windowEl.classList.add('active');
      if (windowEl.id === 'files-window') {
        displayFiles();
      } else if (windowEl.id === 'notepad-window') {
        loadNotepadState();
        renderTabs();
        updateEditor();
      }
    }

    function closeWindow(windowEl) {
      windowEl.classList.remove('active');
    }

    document.getElementById('open-files').addEventListener('click', () => {
      openWindow(document.getElementById('files-window'));
    });

    document.getElementById('open-notepad').addEventListener('click', () => {
      openWindow(document.getElementById('notepad-window'));
    });

    document.querySelectorAll('.win-close').forEach(btn => {
      btn.addEventListener('click', (e) => {
        const window = e.target.closest('.window');
        closeWindow(window);
      });
    });

    document.querySelectorAll('.window-titlebar').forEach(titlebar => {
      let offsetX = 0;
      let offsetY = 0;
      let isDragging = false;

      titlebar.addEventListener('mousedown', (e) => {
        if (e.target.closest('.win-close')) return;
        isDragging = true;
        const window = e.target.closest('.window');
        const rect = window.getBoundingClientRect();
        offsetX = e.clientX - rect.left;
        offsetY = e.clientY - rect.top;
      });

      document.addEventListener('mousemove', (e) => {
        if (!isDragging) return;
        const window = titlebar.closest('.window');
        window.style.left = (e.clientX - offsetX) + 'px';
        window.style.top = (e.clientY - offsetY) + 'px';
      });

      document.addEventListener('mouseup', () => {
        isDragging = false;
      });
    });

    loadNotepadState();
    displayFiles();
  </script>
</body>
</html>
